/**
 * call this javascript action from Nanoflow if want to close anypop up on page from nanoflow
 * @param {string} txnName
 * @param {MxObject} notification
 * @returns {Promise.<void>}
 */
export async function JS_ESignTxnCompleted(txnName, notification) {
	// BEGIN USER CODE
	const eventName = "ESignTxnCompleted_" + txnName;
	const event = new Event(eventName);
	document.dispatchEvent(event);
	console.log("eventName " + eventName +" triggered")

	const eventName2 = "ESignTxnCompletedWithNotification_" + txnName;
	const event2 = new CustomEvent(eventName2, {
        detail: {
            txnName: txnName,
            notification: notification 
        }
    });
	document.dispatchEvent(event2);
	console.debug("eventName " + eventName2 +" triggered with notification data")
	// END USER CODE
}
